<script>
function erroVelocidade(msg){document.getElementById('erro-velocidade-texto').textContent=msg;document.getElementById('erro-velocidade').style.display='flex';document.getElementById('resultado-velocidade').classList.remove('show');}
function limparErroVelocidade(){document.getElementById('erro-velocidade').style.display='none';}
function calcularVelocidadeMedia(){const distancia=parseFloat(document.getElementById('distancia-media').value);const tempo=parseFloat(document.getElementById('tempo-media').value);limparErroVelocidade();if(isNaN(distancia)||isNaN(tempo)||distancia<=0||tempo<=0){erroVelocidade('Informe distï¿½ncia e tempo maiores que zero.');return;}const velocidade=distancia/tempo;document.getElementById('velocidade-valor').textContent=fmtNum(velocidade,2)+' km/h';document.getElementById('velocidade-detalhe').textContent='Fï¿½rmula usada: distï¿½ncia ï¿½ tempo = '+fmtNum(distancia,2)+' ï¿½ '+fmtNum(tempo,2)+'.';showResult('resultado-velocidade');}
function limparVelocidadeMedia(){document.getElementById('distancia-media').value='';document.getElementById('tempo-media').value='';document.getElementById('resultado-velocidade').classList.remove('show');limparErroVelocidade();}
function copiarVelocidadeMedia(button){if(!document.getElementById('resultado-velocidade').classList.contains('show')){erroVelocidade('Calcule a velocidade antes de copiar o resultado.');return;}copyToClipboard('Velocidade mï¿½dia: '+document.getElementById('velocidade-valor').textContent,button);}
</script>
